5	#include "Python.h"
6	#include "numpy/arrayobject.h"
7	
8	#include <memory>
9	#include <new>
10	
11	//
12	// This is used for rank keeping.
13	//
14	class Mediator
15	{
16	public:
17	  int *mem;  // Single array of ints to hold the memory for `pos` and `heap`.
18	  int *pos;  // index into `heap` for each value
19	  int *heap; // max/rank/min heap holding indexes into `data`.
20	  int N;     // allocated size.
21	  int idx;   // position in circular queue
22	  int minCt; // count of items in min heap
23	  int maxCt; // count of items in max heap
24	
25	  //
26	  // This constructor will throw an exception if memory allocation
27	  // fails.  The caller *must* handle this exception so that it
28	  // does not propagate out to Python-land.
29	  //
30	  Mediator(int nItems, int rank) {
31	    mem = new int[2 * nItems];  // Might throw std::bad_alloc
32	    pos = mem;                  // `pos` uses the first `nItems` elements of `mem`.
33	    heap = mem + nItems + rank; // `heap` uses the second `nItems`; it actually
34	                                // points to `rank` elements into the second
35	                                // block of `nItems` elements.
36	    N = nItems;
37	    idx = 0;
38	    minCt = nItems - rank - 1;
39	    maxCt = rank;
40	    while (nItems--) {
41	      pos[nItems] = nItems - rank;
42	      heap[pos[nItems]] = nItems;
43	    }
44	  }
45	
46	  ~Mediator() {
47	    delete [] mem;
48	  }
49	};
50	
51	typedef enum {
52	  NEAREST = 0,
53	  WRAP = 1,
54	  REFLECT = 2,
55	  MIRROR = 3,
56	  CONSTANT = 4,
57	} Mode;
58	
59	/*--- Helper Functions ---*/
60	
61	// returns 1 if heap[i] < heap[j]
62	template <typename T> inline int mmless(T *data, Mediator *m, int i, int j) {
63	  return (data[m->heap[i]] < data[m->heap[j]]);
64	}
65	
66	// swaps items i&j in heap, maintains indexes
67	int mmexchange(Mediator *m, int i, int j) {
68	  int t = m->heap[i];
69	  m->heap[i] = m->heap[j];
70	  m->heap[j] = t;
71	  m->pos[m->heap[i]] = i;
72	  m->pos[m->heap[j]] = j;
73	  return 1;
74	}
75	
76	// swaps items i & j if i < j;  returns true if swapped
77	template <typename T> inline int mmCmpExch(T *data, Mediator *m, int i, int j) {
78	  return (mmless(data, m, i, j) && mmexchange(m, i, j));
79	}
80	
81	// maintains minheap property for all items below i.
82	template <typename T> void minSortDown(T *data, Mediator *m, int i) {
83	  for (i *= 2; i <= m->minCt; i *= 2) {
84	    if (i < m->minCt && mmless(data, m, i + 1, i)) {
85	      ++i;
86	    }
87	    if (!mmCmpExch(data, m, i, i / 2)) {
88	      break;
89	    }
90	  }
91	}
92	
93	// maintains maxheap property for all items below i. (negative indexes)
94	template <typename T> void maxSortDown(T *data, Mediator *m, int i) {
95	  for (i *= 2; i >= -m->maxCt; i *= 2) {
96	    if (i > -m->maxCt && mmless(data, m, i, i - 1)) {
97	      --i;
98	    }
99	    if (!mmCmpExch(data, m, i / 2, i)) {
100	      break;
101	    }
102	  }
103	}
104	
105	// maintains minheap property for all items above i, including the rank
106	// returns true if rank changed
107	template <typename T> inline int minSortUp(T *data, Mediator *m, int i) {
108	  while (i > 0 && mmCmpExch(data, m, i, i / 2))
109	    i /= 2;
110	  return (i == 0);
111	}
112	
113	// maintains maxheap property for all items above i, including rank
114	// returns true if rank changed
115	template <typename T> inline int maxSortUp(T *data, Mediator *m, int i) {
116	  while (i < 0 && mmCmpExch(data, m, i / 2, i))
117	    i /= 2;
118	  return (i == 0);
119	}
120	
121	/*--- Public Interface ---*/
122	
123	// Inserts item, maintains rank in O(lg nItems)
124	template <typename T> void MediatorInsert(T *data, Mediator *m, T v) {
125	  int p = m->pos[m->idx];
126	  T old = data[m->idx];
127	  data[m->idx] = v;
128	  m->idx++;
129	  if (m->idx == m->N) {
130	    m->idx = 0;
131	  }
132	
133	  if (p > 0) // new item is in minHeap
134	  {
135	    if (v > old) {
136	      minSortDown(data, m, p);
137	      return;
138	    }
139	    if (minSortUp(data, m, p) && mmCmpExch(data, m, 0, -1)) {
140	      maxSortDown(data, m, -1);
141	    }
142	  } else if (p < 0) // new item is in maxheap
143	  {
144	    if (v < old) {
145	      maxSortDown(data, m, p);
146	      return;
147	    }
148	    if (maxSortUp(data, m, p) && mmCmpExch(data, m, 1, 0)) {
149	      minSortDown(data, m, 1);
150	    }
151	  } else // new item is at rank
152	  {
153	    if (maxSortUp(data, m, -1)) {
154	      maxSortDown(data, m, -1);
155	    }
156	    if (minSortUp(data, m, 1)) {
157	      minSortDown(data, m, 1);
158	    }
159	  }
160	}
161	
162	//
163	// _rank_filter() requires the allocation of memory.  If the allocation fails,
164	// the function returns -1.  Otherwise it returns 0.
165	//
166	template <typename T>
167	int _rank_filter(T *in_arr, int rank, int arr_len, int win_len, T *out_arr,
168	                  int mode, T cval, int origin) {
169	  int i, arr_len_thresh, lim = (win_len - 1) / 2 - origin;
170	  int lim2 = arr_len - lim;
171	  /* Note: `arr_len == 1` is the only case implemented here for `lim2 < 0`; the calling code */
172	  /* in _filters.py ensures that this function isn't called otherwise. xref gh-23293 for details. */
173	  if (lim2 < 0 && arr_len == 1) {
174	      switch (mode) {
175	          case REFLECT:
176	          case NEAREST:
177	          case WRAP:
178	          case MIRROR:
179	              out_arr[0] = in_arr[0];
180	              return 0;
181	          case CONSTANT:
182	              if (win_len == 1) {
183	                  out_arr[0] = in_arr[0];
184	              }
185	              else {
186	                  out_arr[0] = cval;
187	              }
188	              return 0;
189	      }
190	  }
191	  int offset;
192	  std::unique_ptr<Mediator> m;
193	  std::unique_ptr<T[]> data;
194	  try {
195	    m = std::make_unique<Mediator>(win_len, rank);
196	    data = std::unique_ptr<T[]>(new T[win_len]());
197	  } catch (std::bad_alloc&) {
198	    return -1;
199	  }
200	
201	  switch (mode) {
202	  case REFLECT:
203	    for (i = win_len - lim - 1; i > -1; i--) {
204	      MediatorInsert(data.get(), m.get(), in_arr[i]);
205	    }
206	    break;
207	  case CONSTANT:
208	    for (i = win_len - lim; i > 0; i--) {
209	      MediatorInsert(data.get(), m.get(), cval);
210	    }
211	    break;
212	  case NEAREST:
213	    for (i = win_len - lim; i > 0; i--) {
214	      MediatorInsert(data.get(), m.get(), in_arr[0]);
215	    }
216	    break;
217	  case MIRROR:
218	    for (i = win_len - lim; i > 0; i--) {
219	      MediatorInsert(data.get(), m.get(), in_arr[i]);
220	    }
221	    break;
222	  case WRAP:
223	    if (win_len % 2 == 0) {
224	        offset = 2;
225	    }
226	    else {
227	        offset = 0;
228	    }
229	    for (i = arr_len - lim - offset - 2 * origin; i < arr_len; i++) {
230	      MediatorInsert(data.get(), m.get(), in_arr[i]);
231	    }
232	    break;
233	  }
234	
235	  for (i = 0; i < lim; i++) {
236	    MediatorInsert(data.get(), m.get(), in_arr[i]);
237	  }
238	  for (i = lim; i < arr_len; i++) {
239	    MediatorInsert(data.get(), m.get(), in_arr[i]);
240	    out_arr[i - lim] = data[m->heap[0]];
241	  }
242	  switch (mode) {
243	  case REFLECT:
244	    arr_len_thresh = arr_len - 1;
245	    for (i = 0; i < lim; i++) {
246	      MediatorInsert(data.get(), m.get(), in_arr[arr_len_thresh - i]);
247	      out_arr[lim2 + i] = data[m->heap[0]];
248	    }
249	    break;
250	  case CONSTANT:
251	    for (i = 0; i < lim; i++) {
252	      MediatorInsert(data.get(), m.get(), cval);
253	      out_arr[lim2 + i] = data[m->heap[0]];
254	    }
255	    break;
256	  case NEAREST:
257	    arr_len_thresh = arr_len - 1;
258	    for (i = 0; i < lim; i++) {
259	      MediatorInsert(data.get(), m.get(), in_arr[arr_len_thresh]);
260	      out_arr[lim2 + i] = data[m->heap[0]];
261	    }
262	    break;
263	  case MIRROR:
264	    arr_len_thresh = arr_len - 2;
265	    for (i = 0; i < lim; i++) {
266	      MediatorInsert(data.get(), m.get(), in_arr[arr_len_thresh - i]);
267	      out_arr[lim2 + i] = data[m->heap[0]];
268	    }
269	    break;
270	  case WRAP:
271	    for (i = 0; i < lim; i++) {
272	      MediatorInsert(data.get(), m.get(), in_arr[i]);
273	      out_arr[lim2 + i] = data[m->heap[0]];
274	    }
275	    break;
276	  }
277	  return 0;
278	}
279	
280	
281	// Python wrapper for rank_filter
282	static PyObject *rank_filter(PyObject *self, PyObject *args) {
283	  PyObject *in_arr_obj, *out_arr_obj, *cval_obj;
284	  int rank, arr_len, win_len, mode, origin, type;
285	  int rank_filter_status = 0;
286	
287	  if (!PyArg_ParseTuple(args, "OiiOiOi", &in_arr_obj, &rank, &win_len,
288	                        &out_arr_obj, &mode, &cval_obj, &origin)) {
289	    return NULL;
290	  }
291	
292	  PyArrayObject *in_arr = (PyArrayObject *)PyArray_FROM_OTF(
293	      in_arr_obj, NPY_NOTYPE, NPY_ARRAY_IN_ARRAY);
294	  if (in_arr == NULL) {
295	    return NULL;
296	  }
297	  PyArrayObject *out_arr = (PyArrayObject *)PyArray_FROM_OTF(
298	      out_arr_obj, NPY_NOTYPE, NPY_ARRAY_INOUT_ARRAY2);
299	  if (out_arr == NULL) {
300	    Py_DECREF(in_arr);
301	    return NULL;
302	  }
303	
304	  arr_len = PyArray_SIZE(in_arr);
305	  type = PyArray_TYPE(in_arr);
306	
307	  switch (type) { // the considered types are float, double, int64
308	  case NPY_FLOAT: {
309	    float *c_in_arr = (float *)PyArray_DATA(in_arr);
310	    float *c_out_arr = (float *)PyArray_DATA(out_arr);
311	    float cval = (float)PyFloat_AsDouble(cval_obj);
312	    rank_filter_status = _rank_filter(c_in_arr, rank, arr_len, win_len, c_out_arr,
313	                                      mode, cval, origin);
314	    break;
315	  }
316	  case NPY_DOUBLE: {
317	    double *c_in_arr = (double *)PyArray_DATA(in_arr);
318	    double *c_out_arr = (double *)PyArray_DATA(out_arr);
319	    double cval = PyFloat_AsDouble(cval_obj);
320	    rank_filter_status = _rank_filter(c_in_arr, rank, arr_len, win_len, c_out_arr,
321	                                      mode, cval, origin);
322	    break;
323	  }
324	  case NPY_INT64: {
325	    int64_t *c_in_arr = (int64_t *)PyArray_DATA(in_arr);
326	    int64_t *c_out_arr = (int64_t *)PyArray_DATA(out_arr);
327	    int64_t cval = PyLong_AsLongLong(cval_obj);
328	    rank_filter_status = _rank_filter(c_in_arr, rank, arr_len, win_len, c_out_arr,
329	                                      mode, cval, origin);
330	    break;
331	  }
332	  default:
333	    PyErr_SetString(PyExc_TypeError, "Unsupported array type");
334	    break;
335	  }
336	  if (rank_filter_status == -1) {
337	    PyErr_SetString(PyExc_MemoryError, "failed to allocate memory for rank filter");
338	  }
339	  Py_DECREF(in_arr);
340	  Py_DECREF(out_arr);
341	  if (PyErr_Occurred()) {
342	    return NULL;
343	  }
344	  Py_RETURN_NONE;
345	}
346	
347	// define the module methods
348	static PyMethodDef myMethods[] = {
349	    {"rank_filter", rank_filter, METH_VARARGS, "1D rank filter"},
350	    {NULL, NULL, 0, NULL}};
351	
352	
353	static int
354	_rank_filter_1d_module_exec(PyObject *module)
355	{
356	    (void)module;  /* unused */
357	
358	    if (_import_array() < 0) { return -1; }
359	
360	    return 0;
361	}
362	
363	
364	static PyModuleDef_Slot _rank_filter_1d_slots[] = {
365	    {Py_mod_exec, (void*)_rank_filter_1d_module_exec},
366	    {Py_mod_multiple_interpreters, Py_MOD_PER_INTERPRETER_GIL_SUPPORTED},
367	#if PY_VERSION_HEX >= 0x030d00f0  /* Python 3.13+ */
368	    {Py_mod_gil, Py_MOD_GIL_NOT_USED},
369	#endif
370	    {0, NULL},
371	};
372	
373	
374	// define the module
375	// Designated initializers require C99 or C++20; hence the use of C++17 style initialization.
376	// CAUTION: Even then, C++ requires the order of the fields preserved.
377	static struct PyModuleDef _rank_filter_1d = {
378	    /* m_base     */ PyModuleDef_HEAD_INIT,
379	    /* m_name     */ "_rank_filter_1d",
380	    /* m_doc      */ "1D rank filter module",
381	    /* m_size     */ 0,
382	    /* m_methods  */ myMethods,
383	    /* m_slots    */ _rank_filter_1d_slots,
384	    /* m_traverse */ NULL,
385	    /* m_clear    */ NULL,
386	    /* m_free     */ NULL
387	};
388	
389	
390	// init the module
391	PyMODINIT_FUNC
392	PyInit__rank_filter_1d(void)
393	{
394	    return PyModuleDef_Init(&_rank_filter_1d);
395	}
